<template>
    <div class="edit_view" :style='{}'>
        <div class="breadcrumb-wrapper" style="width: 100%;">
            <div class="bread_view">
                <el-breadcrumb separator="—" class="breadcrumb">
                    <el-breadcrumb-item class="first_breadcrumb" :to="{ path: '/' }">首页</el-breadcrumb-item>
                    <el-breadcrumb-item class="second_breadcrumb" v-for="(item,index) in breadList" :key="index">
                        {{item.name}}
                    </el-breadcrumb-item>
                </el-breadcrumb>
            </div>
        </div>
        <el-form ref="formRef" :model="form" class="add_form" label-width="120px" :rules="rules">
            <el-row>
                <el-col :span="12">
                    <el-form-item label="投诉编号" prop="tousubianhao">
                        <el-input class="list_inp" v-model="form.tousubianhao" placeholder="请输入投诉编号"
                                  readonly></el-input>
                    </el-form-item>
                </el-col>
                <el-col :span="12">
                    <el-form-item label="投诉时间" prop="tousushijian">
                        <el-date-picker
                                class="list_date"
                                v-model="form.tousushijian"
                                format="YYYY-MM-DD HH:mm:ss"
                                value-format="YYYY-MM-DD HH:mm:ss"
                                type="datetime"
                                style="width:100%;"
                                :readonly="!isAdd||disabledForm.tousushijian?true:false"
                                placeholder="请选择投诉时间"/>
                    </el-form-item>
                </el-col>
                <el-col :span="12">
                    <el-form-item label="投标账号" prop="toubiaozhanghao">
                        <el-input class="list_inp" v-model="form.toubiaozhanghao" placeholder="投标账号"
                                  type="text" :readonly="!isAdd||disabledForm.toubiaozhanghao?true:false"/>
                    </el-form-item>
                </el-col>

                <el-col :span="12">
                    <el-form-item label="投标人姓名" prop="toubiaorenxingming">
                        <el-input class="list_inp" v-model="form.toubiaorenxingming" placeholder="投标人姓名"
                                  type="text" :readonly="!isAdd||disabledForm.toubiaorenxingming?true:false"/>
                    </el-form-item>
                </el-col>

                <el-col :span="12">
                    <el-form-item label="手机号" prop="shoujihao">
                        <el-input class="list_inp" v-model="form.shoujihao" placeholder="手机号"
                                  type="text" :readonly="!isAdd||disabledForm.shoujihao?true:false"/>
                    </el-form-item>
                </el-col>

                <el-col :span="24">
                    <el-form-item label="投诉内容" prop="tousuneirong">
                        <editor class="list_editor" :value="form.tousuneirong" placeholder="请输入投诉内容"
                                :readonly="!isAdd||disabledForm.tousuneirong?true:false"
                                @change="(e)=>editorChange(e,'tousuneirong')"></editor>
                    </el-form-item>
                </el-col>
            </el-row>
            <div class="formModel_btn_box">
                <el-button class="formModel_cancel" @click="backClick">取消</el-button>
                <el-button class="formModel_confirm"
                           @click="save"
                           type="success"
                >
                    保存
                </el-button>
            </div>
        </el-form>
    </div>
</template>
<script setup>
    import {
        ref,
        getCurrentInstance,
        watch,
        onUnmounted,
        onMounted,
        nextTick,
        computed
    } from 'vue';
    import {
        useRoute,
        useRouter
    } from 'vue-router';

    const context = getCurrentInstance()?.appContext.config.globalProperties;
    const route = useRoute()
    const router = useRouter()
    //基础信息
    const tableName = 'tousuxinxi'
    const formName = '投诉信息'
    //基础信息
    const breadList = ref([{
        name: formName
    }])
    //获取唯一标识
    const getUUID = () => {
        return new Date().getTime();
    }
    //form表单
    const form = ref({
        tousubianhao: getUUID(),
        tousuneirong: '',
        tousushijian: '',
        toubiaozhanghao: '',
        toubiaorenxingming: '',
        shoujihao: '',
        sfsh: '待审核',
        shhf: '',
    })
    const formRef = ref(null)
    const id = ref(0)
    const type = ref('')
    const disabledForm = ref({
        tousubianhao: false,
        tousuneirong: false,
        tousushijian: false,
        toubiaozhanghao: false,
        toubiaorenxingming: false,
        shoujihao: false,
        sfsh: false,
        shhf: false,
    })
    const isAdd = ref(false)
    //表单验证
    //匹配整数
    const validateIntNumber = (rule, value, callback) => {
        if (!value) {
            callback();
        } else if (!context?.$toolUtil.isIntNumer(value)) {
            callback(new Error("请输入整数"));
        } else {
            callback();
        }
    }
    //匹配数字
    const validateNumber = (rule, value, callback) => {
        if (!value) {
            callback();
        } else if (!context?.$toolUtil.isNumber(value)) {
            callback(new Error("请输入数字"));
        } else {
            callback();
        }
    }
    //匹配手机号码
    const validateMobile = (rule, value, callback) => {
        if (!value) {
            callback();
        } else if (!context?.$toolUtil.isMobile(value)) {
            callback(new Error("请输入正确的手机号码"));
        } else {
            callback();
        }
    }
    //匹配电话号码
    const validatePhone = (rule, value, callback) => {
        if (!value) {
            callback();
        } else if (!context?.$toolUtil.isPhone(value)) {
            callback(new Error("请输入正确的电话号码"));
        } else {
            callback();
        }
    }
    //匹配邮箱
    const validateEmail = (rule, value, callback) => {
        if (!value) {
            callback();
        } else if (!context?.$toolUtil.isEmail(value)) {
            callback(new Error("请输入正确的邮箱地址"));
        } else {
            callback();
        }
    }
    //匹配身份证
    const validateIdCard = (rule, value, callback) => {
        if (!value) {
            callback();
        } else if (!context?.$toolUtil.checkIdCard(value)) {
            callback(new Error("请输入正确的身份证号码"));
        } else {
            callback();
        }
    }
    //匹配网站地址
    const validateUrl = (rule, value, callback) => {
        if (!value) {
            callback();
        } else if (!context?.$toolUtil.isURL(value)) {
            callback(new Error("请输入正确的URL地址"));
        } else {
            callback();
        }
    }
    const rules = ref({
        tousubianhao: [],
        tousuneirong: [
            {required: true, message: '请输入', trigger: 'blur'},
        ],
        tousushijian: [],
        toubiaozhanghao: [],
        toubiaorenxingming: [],
        shoujihao: [],
        sfsh: [],
        shhf: [],
    })
    //methods

    //methods
    //获取info
    const getInfo = () => {
        context?.$http({
            url: `${tableName}/info/${id.value}`,
            method: 'get'
        }).then(res => {
            let reg = new RegExp('../../../file', 'g')
            res.data.data.tousuneirong = res.data.data.tousuneirong.replace(reg, '../../../bidding/file');
            form.value = res.data.data
        })
    }
    const crossRow = ref('')
    const crossTable = ref('')
    const crossTips = ref('')
    const crossColumnName = ref('')
    const crossColumnValue = ref('')
    //初始化
    const init = (formId = null, formType = 'add', formNames = '', row = null, table = null, statusColumnName = null, tips = null, statusColumnValue = null) => {
        form.value.tousushijian = context?.$toolUtil.getCurDateTime()
        if (formId) {
            id.value = formId
            type.value = formType
        }
        if (formType == 'add') {
            isAdd.value = true
        } else if (formType == 'info') {
            isAdd.value = false
            getInfo()
        } else if (formType == 'edit') {
            isAdd.value = true
            getInfo()
        } else if (formType == 'cross') {
            isAdd.value = true
            // getInfo()
            for (let x in row) {
                if (x == 'tousubianhao') {
                    form.value.tousubianhao = row[x];
                    disabledForm.value.tousubianhao = true;
                    continue;
                }
                if (x == 'tousuneirong') {
                    form.value.tousuneirong = row[x];
                    disabledForm.value.tousuneirong = true;
                    continue;
                }
                if (x == 'tousushijian') {
                    form.value.tousushijian = row[x];
                    disabledForm.value.tousushijian = true;
                    continue;
                }
                if (x == 'toubiaozhanghao') {
                    form.value.toubiaozhanghao = row[x];
                    disabledForm.value.toubiaozhanghao = true;
                    continue;
                }
                if (x == 'toubiaorenxingming') {
                    form.value.toubiaorenxingming = row[x];
                    disabledForm.value.toubiaorenxingming = true;
                    continue;
                }
                if (x == 'shoujihao') {
                    form.value.shoujihao = row[x];
                    disabledForm.value.shoujihao = true;
                    continue;
                }
            }
            if (row) {
                crossRow.value = row
            }
            if (table) {
                crossTable.value = table
            }
            if (tips) {
                crossTips.value = tips
            }
            if (statusColumnName) {
                crossColumnName.value = statusColumnName
            }
            if (statusColumnValue) {
                crossColumnValue.value = statusColumnValue
            }
            form.value.sfsh = '待审核'
        }
        context?.$http({
            url: `${context?.$toolUtil.storageGet('frontSessionTable')}/session`,
            method: 'get'
        }).then(res => {
            var json = res.data.data
            if (json.hasOwnProperty('toubiaozhanghao') && context?.$toolUtil.storageGet("frontRole") != "管理员") {
                form.value.toubiaozhanghao = json.toubiaozhanghao
                disabledForm.value.toubiaozhanghao = true;
            }
            if (json.hasOwnProperty('toubiaorenxingming') && context?.$toolUtil.storageGet("frontRole") != "管理员") {
                form.value.toubiaorenxingming = json.toubiaorenxingming
                disabledForm.value.toubiaorenxingming = true;
            }
            if (json.hasOwnProperty('shoujihao') && context?.$toolUtil.storageGet("frontRole") != "管理员") {
                form.value.shoujihao = json.shoujihao
                disabledForm.value.shoujihao = true;
            }
            if (localStorage.getItem('autoSave')) {
                localStorage.removeItem('autoSave')
                save()
            }
        })
    }
    //初始化
    //取消
    const backClick = () => {
        history.back()
    }
    //富文本数据回调
    const editorChange = (e, name) => {
        form.value[name] = e
    }
    //提交
    const save = () => {
        var table = crossTable.value
        var objcross = JSON.parse(JSON.stringify(crossRow.value))
        let crossUserId = ''
        let crossRefId = ''
        let crossOptNum = ''
        if (type.value == 'cross') {
            if (crossColumnName.value != '') {
                if (!crossColumnName.value.startsWith('[')) {
                    for (let o in objcross) {
                        if (o == crossColumnName.value) {
                            objcross[o] = crossColumnValue.value
                        }
                    }
                    //修改跨表数据
                    changeCrossData(objcross)
                } else {
                    crossUserId = context?.$toolUtil.storageGet('userid')
                    crossRefId = objcross['id']
                    crossOptNum = crossColumnName.value.replace(/\[/, "").replace(/\]/, "")
                }
            }
        }
        formRef.value.validate((valid) => {
            if (valid) {
                if (crossUserId && crossRefId) {
                    form.value.crossuserid = crossUserId
                    form.value.crossrefid = crossRefId
                    let params = {
                        page: 1,
                        limit: 1000,
                        crossuserid: form.value.crossuserid,
                        crossrefid: form.value.crossrefid,
                    }
                    context?.$http({
                        url: `${tableName}/page`,
                        method: 'get',
                        params: params
                    }).then(res => {
                        if (res.data.data.total >= crossOptNum) {
                            context?.$toolUtil.message(`${crossTips.value}`, 'error')
                            return false
                        } else {
                            context?.$http({
                                url: `${tableName}/${!form.value.id ? "save" : "update"}`,
                                method: 'post',
                                data: form.value
                            }).then(res => {
                                context?.$toolUtil.message(`操作成功`, 'success')
                                history.back()
                            })
                        }
                    })
                } else {
                    context?.$http({
                        url: `${tableName}/${!form.value.id ? "save" : "update"}`,
                        method: 'post',
                        data: form.value
                    }).then(res => {
                        context?.$toolUtil.message(`操作成功`, 'success')
                        history.back()
                    })
                }
            }
        })
    }
    //修改跨表数据
    const changeCrossData = (row) => {
        if (type.value == 'cross') {
            context?.$http({
                url: `${crossTable.value}/update`,
                method: 'post',
                data: row
            }).then(res => {
            })
        }
    }
    onMounted(() => {
        type.value = route.query.type ? route.query.type : 'add'
        let row = null
        let table = null
        let statusColumnName = null
        let tips = null
        let statusColumnValue = null
        if (type.value == 'cross') {
            row = context?.$toolUtil.storageGet('crossObj') ? JSON.parse(context?.$toolUtil.storageGet('crossObj')) : {}
            table = context?.$toolUtil.storageGet('crossTable')
            statusColumnName = context?.$toolUtil.storageGet('crossStatusColumnName')
            tips = context?.$toolUtil.storageGet('crossTips')
            statusColumnValue = context?.$toolUtil.storageGet('crossStatusColumnValue')
        }
        init(route.query.id ? route.query.id : null, type.value, '', row, table, statusColumnName, tips, statusColumnValue)
    })
    onUnmounted(() => {
        Object.keys(localStorage).map(item => {
            if (item.startsWith('cross')) {
                localStorage.removeItem(item)
            }
        })
    })
</script>
<style lang="scss" scoped>
    // 面包屑盒子
    .bread_view {
        :deep(.breadcrumb) {
            .el-breadcrumb__separator {
            }

            .first_breadcrumb {
                .el-breadcrumb__inner {
                }
            }

            .second_breadcrumb {
                .el-breadcrumb__inner {
                }
            }
        }
    }

    // 表单
    .add_form {
        // form item
        :deep(.el-form-item) {
            //label
            .el-form-item__label {
            }

            // 内容盒子
            .el-form-item__content {
                // 输入框
                .list_inp {

                }

                //日期选择器
                .list_date {
                }

                // 富文本
                .list_editor {
                }
            }
        }
    }

    // 按钮盒子
    .formModel_btn_box {
        .formModel_cancel {
        }

        .formModel_cancel:hover {
        }

        .formModel_confirm {
        }

        .formModel_confirm:hover {
        }
    }
</style>
<style>
